import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { createRFQ } from "../api/axios";

const triggerOptions = [
  { value: "bid_received", label: "Bid Received in Last X Minutes" },
  { value: "any_rank_change", label: "Any Rank Change" },
  { value: "l1_rank_change", label: "L1 Rank Change" },
];

const CreateRFQ = () => {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    reference_id: "",
    bid_start_time: "",
    bid_close_time: "",
    forced_close_time: "",
    pickup_date: "",
    trigger_window_minutes: "",
    extension_duration_minutes: "",
    extension_trigger_type: "bid_received",
    status: "active",
  });
  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const validate = () => {
    const err = {};
    if (!form.name.trim()) err.name = "RFQ name is required.";
    if (!form.reference_id.trim()) err.reference_id = "Reference ID is required.";
    if (form.forced_close_time && form.bid_close_time && form.forced_close_time <= form.bid_close_time) {
      err.forced_close_time = "Forced close time must be after bid close time.";
    }
    if (form.bid_start_time && form.bid_close_time && form.bid_start_time >= form.bid_close_time) {
      err.bid_start_time = "Bid start time must be before bid close time.";
    }
    if (!form.trigger_window_minutes) err.trigger_window_minutes = "Trigger window is required.";
    if (!form.extension_duration_minutes) err.extension_duration_minutes = "Extension duration is required.";
    return err;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const err = validate();
    setErrors(err);
    if (Object.keys(err).length > 0) return;
    setSubmitting(true);
    try {
      const payload = {
        ...form,
        bid_start_time: new Date(form.bid_start_time).toISOString(),
        bid_close_time: new Date(form.bid_close_time).toISOString(),
        forced_close_time: new Date(form.forced_close_time).toISOString(),
        pickup_date: form.pickup_date,
        trigger_window_minutes: Number(form.trigger_window_minutes),
        extension_duration_minutes: Number(form.extension_duration_minutes),
      };
      await createRFQ(payload);
      navigate("/");
    } catch (error) {
      setErrors({ submit: error.response?.data?.detail || "Failed to create RFQ." });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#f1f5f9] px-4 py-8">
      <div className="mx-auto w-full max-w-[600px] rounded-xl bg-white p-6 shadow-lg sm:p-8">
        <h1 className="mb-6 text-2xl font-bold text-gray-900">Create New RFQ</h1>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">RFQ Name</label>
            <input
              type="text"
              name="name"
              value={form.name}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
            />
            {errors.name && <p className="mt-1 text-xs text-[#dc2626]">{errors.name}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Reference ID</label>
            <input
              type="text"
              name="reference_id"
              value={form.reference_id}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
            />
            {errors.reference_id && <p className="mt-1 text-xs text-[#dc2626]">{errors.reference_id}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Bid Start Date & Time</label>
            <input
              type="datetime-local"
              name="bid_start_time"
              value={form.bid_start_time}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              required
            />
            {errors.bid_start_time && <p className="mt-1 text-xs text-[#dc2626]">{errors.bid_start_time}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Bid Close Date & Time</label>
            <input
              type="datetime-local"
              name="bid_close_time"
              value={form.bid_close_time}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              required
            />
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Forced Bid Close Date & Time</label>
            <input
              type="datetime-local"
              name="forced_close_time"
              value={form.forced_close_time}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              required
            />
            {errors.forced_close_time && <p className="mt-1 text-xs text-[#dc2626]">{errors.forced_close_time}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Pickup / Service Date</label>
            <input
              type="date"
              name="pickup_date"
              value={form.pickup_date}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              required
            />
          </div>

          <hr className="my-5 border-gray-200" />

          <h2 className="text-sm font-semibold text-[#1e3a5f]">Auction Config</h2>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Trigger Window X Minutes</label>
            <input
              type="number"
              name="trigger_window_minutes"
              value={form.trigger_window_minutes}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              min="1"
              required
            />
            {errors.trigger_window_minutes && <p className="mt-1 text-xs text-[#dc2626]">{errors.trigger_window_minutes}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Extension Duration Y Minutes</label>
            <input
              type="number"
              name="extension_duration_minutes"
              value={form.extension_duration_minutes}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              min="1"
              required
            />
            {errors.extension_duration_minutes && <p className="mt-1 text-xs text-[#dc2626]">{errors.extension_duration_minutes}</p>}
          </div>

          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Extension Trigger Type</label>
            <select
              name="extension_trigger_type"
              value={form.extension_trigger_type}
              onChange={handleChange}
              className="w-full rounded-md border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-200"
              required
            >
              {triggerOptions.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
          </div>

          {errors.submit && <p className="text-sm text-[#dc2626]">{errors.submit}</p>}

          <button
            type="submit"
            disabled={submitting}
            className="w-full rounded-md bg-[#16a34a] px-4 py-2.5 text-sm font-semibold text-white shadow hover:bg-green-700 disabled:opacity-70"
          >
            {submitting ? "Creating..." : "Create RFQ"}
          </button>

          <button
            type="button"
            onClick={() => navigate("/")}
            className="w-full rounded-md bg-gray-200 px-4 py-2.5 text-sm font-semibold text-gray-700 hover:bg-gray-300"
          >
            Cancel
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreateRFQ;
